"use strict";parserFactory.register("shubaow.net",()=>new ShubaowParser);class ShubaowParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=[...e.querySelectorAll("div#list dd a")];return this.removeDuplicates(t).map(e=>util.hyperLinkToChapter(e))}removeDuplicates(e){let t=new Set,r=[];for(;0<e.length;){let n=e.pop();t.has(n.href)||(r.push(n),t.add(n.href))}return r.reverse()}findContent(e){return e.querySelector("div#content")}extractTitleImpl(e){return e.querySelector("div#info h1")}extractLanguage(){return"cn"}findChapterTitle(e){return e.querySelector("div.bookname h1").textContent}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div#fmimg")}async fetchChapter(e){return(await HttpClient.wrapFetch(e,this.makeOptions())).responseXML}makeOptions(){return{makeTextDecoder:()=>new TextDecoder("gbk")}}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div#intro")]}cleanInformationNode(e){util.removeChildElementsMatchingSelector(e,"script, .adsbygoogle")}}